"""Optional short stories per place (Wikipedia)."""

SCULPTURE_STORIES: dict[str, str] = {
    "«Рабочий и колхозница»": "Скульптура высотой около 24 м из нержавеющей стали работы В. И. Мухиной создана для Всемирной выставки 1937 года в Париже; в Москве установлена у ВДНХ.",
    "Могила Неизвестного Солдата": "Мемориал в Александровском саду у Кремля в память о погибших в Великой Отечественной войне. Создан по проекту архитекторов Д. И. Бурдина, В. А. Климова, Ю. Р. Рабаева и скульптора Н. В. Томского. Вечный огонь перенесён от Манежа в 1967 году.",
    "Монумент «Покорителям космоса»": "Обелиск в Москве у ВДНХ, установлен в 1964 году в честь достижений СССР в освоении космоса. Изображает взлетающую ракету на струе двигателя.",
    "Памятник А. В. Суворову": "Памятник полководцу А. В. Суворову в Москве; установлен в честь генералиссимуса — участника русско-турецких войн и Итальянского похода.",
    "Памятник А. Д. Меншикову": "Алекса́ндр Дани́лович Ме́ншиков (6 [16] ноября 1673, Москва — 12 [23] ноября 1729, Берёзов, Сибирская губерния) — русский государственный и военный деятель, ближайший сподвижник и фаворит Петра I, генералиссимус (12 мая — 8 сентября 1727 года), адмирал (6 мая — 8 сентября 1727 года). Первый санкт-петербургский генерал-губернатор (1703—1724 и 1725—1727), президент Военной коллегии (1719—1724 и 1726—1727).",
    "Памятник А. Д. Сахарову": "Андре́й Дми́триевич Са́харов (21 мая 1921, Москва — 14 декабря 1989, Москва) — советский физик-теоретик, академик АН СССР, общественный деятель, диссидент и правозащитник. Народный депутат СССР (1989). Один из создателей первой советской водородной бомбы. Народный депутат СССР, автор проекта конституции Союза Советских Республик Европы и Азии. Лауреат Нобелевской премии мира за 1975 год.",
    "Памятник А. И. Герцену": "Памятник Александру Герцену — скульптурный памятник литератору Александру Герцену, расположенный в Москве на Тверском бульваре. Объект культурного наследия народов России регионального значения.",
    "Памятник А. И. Солженицыну": "Лауреат Нобелевской премии по литературе (1970), Государственной премии Российской Федерации (2007) и Государственной премии РСФСР имени М.",
    "Памятник А. Н. Островскому": "Никола́й Алексе́евич Остро́вский (16 (29) сентября 1904, Вилия, Волынская губерния — 22 декабря 1936, Москва) — советский писатель, автор романа «Как закалялась сталь».",
    "Памятник А. Н. Скрябину": " В 1910 году Скрябин создал музыкальную поэму «Прометей» («Поэма огня»), которая стала первым светомузыкальным произведением в мировой истории.",
    "Памятник А. С. Грибоедову": "Памятник Грибоедову — скульптурное изображение драматурга Александра Сергеевича Грибоедова в Москве, в начале Чистопрудного бульвара, недалеко от выхода одноимённой станции метрополитена.",
    "Памятник А. С. Пушкину": "Памятник поэту А. С. Пушкину на Пушкинской площади; один из символов Москвы. Создан скульптором А. М. Опекушиным, открыт в 1880 году.",
    "Памятник А. С. Пушкину (в парке Царицыно)": " На начало 2018 года в столице насчитывалось более 900 различных памятников.",
    "Памятник А. С. Пушкину и Н. Н. Гончаровой": "Дуэль между Александром Сергеевичем Пушкиным и Жоржем де Геккерном (Дантесом) состоялась 27 января (8 февраля) 1837 года на окраине Санкт-Петербурга, в районе Чёрной речки близ Комендантской дачи. Дуэлянты стрелялись на пистолетах. В результате дуэли Пушкин был смертельно ранен и через два дня умер.",
    "Памятник А. де Сент-Экзюпери": "Памятник французскому писателю и лётчику Антуану де Сент-Экзюпери, автору «Маленького принца»; установлен в Москве в честь его связи с авиацией и гуманистическим наследием.",
    "Памятник Булату Окуджаве": "Лауреат Государственной премии СССР (1991).",
    "Памятник В. И. Ленину (в Кремле)": " Служит символом высшего руководства страны (партии и правительства, с 1990 года — президента и правительства).",
    "Памятник В. И. Ленину (у Казанского вокзала)": "Ленингра́дский вокза́л (до 1855 года — Петербу́ргский, с 1855 по 1923 год — Никола́евский, с 1923 по 1924 год — Октя́брьский, с 1924 года — Ленинградский) — железнодорожный вокзал, пассажирский терминал железнодорожной станции Москва-Пассажирская (Москва-Октябрьская, Москва-Пассажирская-Октябрьская), расположенный на Комсомольской площади Москвы.",
    "Памятник В. И. Ленину (у завода «Серп и молот»)": "Председатель Совета народных комиссаров СССР в 1930—1941 годах, народный комиссар иностранных дел СССР в 1939—1946 годах, министр иностранных дел СССР в 1946—1949, 1953—1956 годах.",
    "Памятник В. И. Ленину у Октябрьской площади": "Памятник (Владимиру Ильичу) Ленину — название следующих памятников российскому революционеру Владимиру Ленину:",
    "Памятник В. Маяковскому": "Памятник поэту Владимиру Маяковскому на Триумфальной площади; автор — скульптор А. П. Кибальников, открыт в 1958 году.",
    "Памятник В. С. Высоцкому": "Памятник поэту, барду и актёру Владимиру Высоцкому; установлен у Петровских ворот. Один из самых узнаваемых монументов, посвящённых артисту.",
    "Памятник В. С. Высоцкому (второй)": "Не случайно по итогам опроса ВЦИОМ, проведённого в 2009—2010 гг.",
    "Памятник Г. К. Жукову": "Маргарита Георгиевна Жукова (1929—2010) — советский и российский работник образования и общественный деятель. Дочь Георгия Константиновича Жукова. Возглавляла фонд «Маршал Жуков». Член Союза журналистов России, автор множества публикаций о Г. К. Жукове, совершила более 300 поездок по России, СНГ и дальнему зарубежью с выступлениями о своём отце.",
    "Памятник Е. В. Вучетичу (автору «Родины-матери»)": "Академик АХ СССР (1953; член-корреспондент 1947).",
    "Памятник И. А. Бунину": "Памятник писателю, лауреату Нобелевской премии И. А. Бунину установлен в Москве на Поварской улице.",
    "Памятник И. А. Крылову": "Памятник Ивану Андреевичу Крылову в Москве установлен около Патриарших прудов в Ермолаевском переулке.",
    "Памятник И. К. Айвазовскому": "Памятник русскому художнику-маринисту И. К. Айвазовскому; установлен в Москве в честь его вклада в русское искусство.",
    "Памятник И. С. Тургеневу": " Монумент открыт 4 ноября 1968 года по случаю 150-летнего юбилея со дня рождения русского писателя И.",
    "Памятник К. А. Тимирязеву": "Монумент установлен в 1923 году в Москве на Тверском бульваре у площади Никитские Ворота.",
    "Памятник К. Марксу и Ф. Энгельсу": "Скульптурная группа К. Марксу и Ф. Энгельсу в Москве; установлена у Театральной площади в память о основоположниках марксизма.",
    "Памятник К. Э. Циолковскому": "В 1879 году сдал экзамен на звание народного учителя и до 1921 года преподавал математику и физику в училищах Боровска и Калуги, параллельно пытаясь заинтересовать научное сообщество своими проектами аэропланов и цельнометаллического дирижабля, а впоследствии — и ракетной техники.",
    "Памятник Л. Н. Толстому": "Гранитная скульптура Л. Н. Толстого работы С. Д. Меркурова создана в 1913 году; на нынешнем месте у площади Девичьего поля с 1972 года.",
    "Памятник М. В. Ломоносову": "Памятник учёному и просветителю М. В. Ломоносову; установлен в Москве в честь основателя Московского университета.",
    "Памятник М. В. Фрунзе": "Ми́рский; 21 января [2 февраля] 1885, Пишпек, Семиреченская область — 31 октября 1925[…], Москва) — российский революционер, советский государственный деятель, военачальник Красной армии во время Гражданской войны, военный теоретик.",
    "Памятник М. И. Глинке": "Михаи́л Ива́нович Гли́нка (20 мая [1 июня] 1804, Новоспасское, Смоленская губерния — 15 февраля 1857, Берлин) — русский композитор, наиболее значимый петербургский музыкант николаевской эпохи, один из основоположников русской традиции классической музыки, оказавший определяющее влияние на крупнейших авторов следующих поколений.",
    "Памятник М. И. Калинину": "Памятник советскому государственному деятелю М. И. Калинину; установлен в Москве в районе, носившем его имя (Калининский район, ныне в составе ЦАО).",
    "Памятник М. И. Кутузову": "Михаи́л Илларио́нович Голени́щев-Куту́зов (16 сентября 1747 или 5 [16] сентября 1747, Санкт-Петербург или Псковская провинция, Новгородская губерния — 16 [28] апреля 1813 или 28 апреля 1813, Болеславец) — русский полководец, государственный деятель и дипломат, генерал-фельдмаршал из рода Голенищевых-Кутузовых. Участник русско-турецких войн, главнокомандующий русской армией во время Отечественной войны 1812 года.",
    "Памятник М. Ю. Лермонтову": "Памятник поэту М. Ю. Лермонтову; установлен в Москве в честь автора «Героя нашего времени» и лирики.",
    "Памятник М. Ю. Лермонтову (второй)": "Михаи́л Ю́рьевич Ле́рмонтов (3 [15] октября 1814, Москва — 15 [27] июля 1841, Пятигорск) — русский поэт, прозаик, драматург, художник. Поручик лейб-гвардии Гусарского полка.",
    "Памятник Минину и Пожарскому": "Бронзовый памятник Кузьме Минину и Дмитрию Пожарскому на Красной площади; работа И. П. Мартоса, установлен в 1818 году в честь освобождения Москвы в 1612 году.",
    "Памятник Н. А. Римскому-Корсакову": "Никола́й Андре́евич Ри́мский-Ко́рсаков (6 [18] марта 1844, Тихвин — 8 [21] июня 1908, усадьба Любенск, Санкт-Петербургская губерния) — русский композитор, педагог, дирижёр, писатель, общественный деятель, музыкальный критик; член «Могучей кучки». Среди его сочинений — 15 опер, 3 симфонии, симфонические произведения, инструментальные концерты, кантаты, камерно-инструментальная, вокальная и духовная музыка.",
    "Памятник Н. В. Гоголю": "Памятник писателю Н. В. Гоголю в Москве; на Гоголевском бульваре установлена версия скульптора Н. А. Андреева (1909), на Суворовской площади — другая версия.",
    "Памятник Н. И. Лобачевскому": "Дореволюционные даты приводятся по юлианскому календарю. Никола́й Ива́нович Лобаче́вский (20 ноября [1 декабря] 1792, Нижний Новгород — 12 [24] февраля 1856, Казань) — русский математик, один из первооткрывателей неевклидовой («гиперболической») геометрии, деятель университетского образования и народного просвещения.",
    "Памятник Н. И. Пирогову": "В 2007 году памятнику присвоен статус объекта культурного наследия федерального значения.",
    "Памятник Н. Э. Бауману": "Бауману установлен в Пушкинском сквере на Елоховской площади в Москве в память о российском революционере Николае Эрнестовиче Баумане, открыт 31 октября 1931 года.",
    "Памятник О. И. Янковскому": "братьев Васильевых (1989) и премии Ленинского комсомола (1977).",
    "Памятник П. И. Чайковскому": "Памятник Чайковскому — памятник русскому композитору и дирижёру Петру Ильичу Чайковскому. Расположен в Москве, по Большой Никитской улице, дом 13, перед зданием Московской государственной консерватории.",
    "Памятник Петру I (Зураба Церетели)": "Монумент Петру I на стрелке Москвы-реки и Обводного канала; работа З. К. Церетели, установлен в 1997 году. Высота около 98 м.",
    "Памятник Петру и Февронии": "Днём их памяти является 25 июня (8 июля); 25 декабря 2012 года Священный Синод установил ещё одно празднование святым — в воскресенье перед 6 (19) сентября (перенесение их мощей в 1992 году).",
    "Памятник С. А. Есенину": "Серге́й Алекса́ндрович Есе́нин (21 сентября [3 октября] 1895[…], Константиново, Рязанская губерния — 28 декабря 1925[…], Ленинград, СССР) — русский и советский поэт, писатель. Один из крупнейших поэтов Серебряного века. Представитель новокрестьянской поэзии и лирики, а в более позднем периоде творчества — имажинизма.",
    "Памятник С. В. Рахманинову": "Памятник Сергею Рахманинову установлен в 1999 году в Москве на Страстном бульваре. Авторы монумента — скульпторы О. К. Комов, А. Н. Ковальчук и архитектор Ю. П. Григорьев. Памятник имеет статус заявленного объекта культурного наследия.",
    "Памятник С. П. Королёву": "Серге́й Па́влович Королёв (30 декабря 1906  [12 января 1907] или 12 января 1907, Житомир, Волынская губерния, Российская империя[…] — 14 января 1966[…], Москва, СССР) — советский учёный, конструктор ракетно-космических систем. Дважды Герой Социалистического Труда. Академик АН СССР (1958). Член-корреспондент Академии артиллерийских наук. Председатель Совета главных конструкторов СССР (1946—1966).",
    "Памятник Ф. М. Достоевскому": "Фёдор Миха́йлович Достое́вский (30 октября [11 ноября] 1821, Москва — 28 января [9 февраля] 1881, Санкт-Петербург) — русский писатель, мыслитель, философ и публицист. Член-корреспондент Петербургской академии наук с 1877 года. Классик мировой литературы, по данным ЮНЕСКО, один из самых читаемых писателей в мире.",
    "Памятник Ф. Э. Дзержинскому (снят)": "Один из первых действительных членов Академии художеств СССР (с 1947), народный художник СССР (1943), лауреат двух Сталинских премий первой степени (1941, 1951).",
    "Памятник Шерлоку Холмсу и доктору Ватсону": "Скульптурная композиция у станции метро «Смоленская» в честь героев Конан Дойла и советского телефильма «Приключения Шерлока Холмса и доктора Ватсона».",
    "Памятник Ю. А. Гагарину": "Монумент первому космонавту Ю. А. Гагарину на Ленинском проспекте; высота 42,5 м, постамент напоминает струю ракетного двигателя. Выполнен из титана.",
    "Памятник Ю. В. Никулину": "Герой Социалистического Труда (1990), народный артист СССР (1973), лауреат Государственной премии РСФСР им.",
    "Памятник Юрию Долгорукому": "Памятник основателю Москвы князю Юрию Долгорукому на Тверской площади; установлен в 1954 году перед зданием Моссовета (ныне мэрия Москвы).",
    "Скульптура «Войну и мир» (Толстой)": "Изготовлена в 1950 году в ответ на начавшуюся Корейскую войну скульптором В.",
    "Скульптура «Дети — жертвы пороков взрослых»": "«Де́ти — же́ртвы поро́ков взро́слых» — скульптурная композиция как аллегория борьбы со злом и общественными пороками, установлена на Болотной площади в Москве на территории сквера 800-летия Москвы. Установлена в 2001 году. Автор — художник и скульптор Михаил Шемякин.",
}

